SELECT AVG(energy_forecast) AS average_forecast
FROM energy_forecasts
WHERE node_id = 1;

SELECT COUNT(document_id) AS document_count
FROM node_documents
WHERE node_id = 1;

SELECT node_id, COUNT(image_id) AS total_images
FROM node_images
GROUP BY node_id;

SELECT COUNT(image_id) AS total_images
FROM node_images
WHERE node_id = 1;
